mapper.select:
SELECT s.settlement_id as settlementId, s.gym_id as gymId, g.gym_name as gymName, s.commission, s.settled_at as settledAt, s.commission_rate as commissionRate, s.settle_month as settleMonth, s.status, s.expense_id as expenseId FROM "h_settlement" s LEFT JOIN "h_gym" g ON s.gym_id = g.gym_id
AND s.status = #{pager.searchKeyword}
AND TO_CHAR(s.settle_month, 'YYYY-MM') = #{pager.month}
ORDER BY s.commission DESC ORDER BY s.commission ASC ORDER BY s.settle_month ASC, s.settlement_id ASC ORDER BY s.settle_month DESC, s.settlement_id DESC
LIMIT #{pager.pageSize} OFFSET #{pager.offset}

SELECT COUNT(*)
FROM "h_settlement" s


        AND s.status = #{pager.searchKeyword}


        AND TO_CHAR(s.settle_month, 'YYYY-MM') = #{pager.month}

SELECT s.settlement_id as settlementId, s.gym_id as gymId, g.gym_name as gymName, s.commission, s.settled_at as settledAt, s.commission_rate as commissionRate, s.settle_month as settleMonth, s.status, s.expense_id as expenseId FROM "h_settlement" s LEFT JOIN "h_gym" g ON s.gym_id = g.gym_id
AND s.status = #{pager.searchKeyword}
AND TO_CHAR(s.settle_month, 'YYYY-MM') = #{pager.month}
ORDER BY s.settle_month DESC, s.settlement_id DESC

mapper.update:
UPDATE "h_settlement"
SET status = #{status},
    settled_at = #{settledAt}
WHERE settlement_id = #{settlementId}

mapper.select:
SELECT CAST(COALESCE(SUM(pay_price), 0) * #{rate} AS int8)
FROM "h_payment"
WHERE gym_id = #{gymId} AND pay_date >= #{startDate} AND pay_date <= #{endDate}

SELECT expense_id as expenseId, gym_id as gymId, data_id as dataId, expense_name as expenseName, expense_date as expenseDate, expense_price as expensePrice, expense_rate as expenseRate FROM "h_expense" WHERE gym_id = (SELECT gym_id FROM "h_member" WHERE username = #{username})
AND TO_CHAR(expense_date, 'YYYY-MM') = #{pager.month}
AND expense_name LIKE CONCAT('%', #{pager.searchKeyword}, '%')
ORDER BY expense_price DESC ORDER BY expense_price ASC ORDER BY expense_date ASC, expense_id ASC ORDER BY expense_date DESC, expense_id DESC
LIMIT #{pager.pageSize} OFFSET #{pager.offset}

SELECT COUNT(*) FROM "h_expense" WHERE gym_id = (SELECT gym_id FROM "h_member" WHERE username = #{username})
AND TO_CHAR(expense_date, 'YYYY-MM') = #{pager.month}
AND expense_name LIKE CONCAT('%', #{pager.searchKeyword}, '%')

SELECT COALESCE(SUM(expense_price), 0) FROM "h_expense" WHERE gym_id = (SELECT gym_id FROM "h_member" WHERE username = #{username})
AND TO_CHAR(expense_date, 'YYYY-MM') = #{pager.month}
AND expense_name LIKE CONCAT('%', #{pager.searchKeyword}, '%')

SELECT COUNT(*) 
FROM "h_settlement" 
WHERE gym_id = #{gymId} 
  AND settle_month = #{settleMonth}
